def handler(event, context):
    qs = (event or {}).get("queryStringParameters") or {}
    sql = (qs.get("sql") or "SELECT now() AS server_time").strip()

    if not sql.lower().startswith("select"):
        return response(400, {"error": "Only SELECT statements are allowed."})

    limit = qs.get("limit")
    try:
        limit_int = int(limit) if limit is not None else None
    except ValueError:
        return response(400, {"error": "Invalid limit."})

    if limit_int is not None:
        if limit_int < 1 or limit_int > 1000:
            return response(400, {"error": "limit must be between 1 and 1000."})
        sql = f"SELECT * FROM ({sql}) AS q LIMIT {limit_int}"

